<section class="admin-shell"><?php require __DIR__.'/_nav.php';?><div class="admin-main"><div class="admin-head"><div><span class="eyebrow">AI QUALITY REVIEW</span><h1>Unanswered Questions</h1><p>Review frequent unknown queries and add verified answers to the knowledge base.</p></div><a class="btn" href="<?=url('admin/ai-knowledge')?>">Add Knowledge</a></div><div class="admin-panel"><div class="table-wrap"><table><thead><tr><th>Question</th><th>Language</th><th>Occurrences</th><th>Last Seen</th><th>Status</th><th>Review</th></tr></thead><tbody><?php foreach($rows as$x):?><tr><td><?=e($x['query_text'])?></td><td><?=e(strtoupper($x['language']))?></td><td><?=$x['occurrence_count']?></td><td><?=date('d M Y, h:i A',strtotime($x['last_seen_at']))?></td><td><?=e($x['status'])?></td><td><form class="inline-update" method="post" action="<?=url('admin/ai-unanswered')?>"><?=csrf_field()?><input type="hidden" name="id" value="<?=$x['id']?>"><select name="status"><?php foreach(['new','reviewing','resolved','ignored']as$s):?><option <?=$x['status']===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select><input name="note" value="<?=e($x['resolution_note'])?>" placeholder="Resolution note"><button class="btn small">Save</button></form></td></tr><?php endforeach;?></tbody></table></div><?php if(!$rows):?><div class="empty">No unanswered questions yet.</div><?php endif;?></div></div></section>
